// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AgentCase) predicate.AgentCase {
	return predicate.AgentCase(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AgentCase) predicate.AgentCase {
	return predicate.AgentCase(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AgentCase) predicate.AgentCase {
	return predicate.AgentCase(sql.NotPredicates(p))
}
